    pub fn parseAll(self: *ConfigParser) !std.ArrayListAligned(Command, null) {
        var commands: std.ArrayListAligned(Command, null) = .empty;
        errdefer {
            for (commands.items) |*cmd| cmd.deinit(self.allocator);
            commands.deinit(self.allocator);
